export const meta = { name: 'deep-review', description: 'deep-review v3 pipeline: phases 3-7 orchestration (Summarize, Discover, Merge, Verify, Validate, Filter, Challenge, Report)', version: '3.0.0-dev', phases: ['summarize', 'discover', 'merge', 'verify', 'validate', 'filter', 'challenge', 'report'] };
const PIPELINE_VERSION = '3.0.0-dev';
// GENERATED by workflows/build.js — do not edit by hand.
// --- findingDedup.js ---
// findingDedup.js — canonical dedup by id. NDJSON (priority 2) beats text (1).
// Single source of truth: reused by mergeFindings and filterFindings.
function dedupById(ndjsonFindings, textFindings) {
  const seen = new Map(); // id -> { finding, priority }
  let duplicatesResolved = 0;
  let droppedNoId = 0;

  const add = (finding, priority) => {
    const fid = finding.id;
    if (fid === undefined || fid === null) { droppedNoId += 1; return; }
    if (seen.has(fid)) {
      if (priority > seen.get(fid).priority) seen.set(fid, { finding, priority });
      duplicatesResolved += 1;
    } else {
      seen.set(fid, { finding, priority });
    }
  };

  for (const findings of Object.values(textFindings || {})) for (const f of findings) add(f, 1);
  for (const findings of Object.values(ndjsonFindings || {})) for (const f of findings) add(f, 2);

  return { merged: [...seen.values()].map((v) => v.finding), duplicatesResolved, droppedNoId };
}

// --- filterFindings.js ---
// filterFindings.js — JS twin of scripts/filter_findings.py (Phase 6 filtering).
// Part 1 (this task): normalize / thresholds / injection / exclusions / REVIEW.md
// parsing. Part 2 (Task 5): disagreement detection, tagging, dedupCrossAgent,
